// Build Scout discovery payload from the DB webhook event
// Supabase DB webhook sends: { type, table, record, old_record, schema }
const event = $input.first().json;
const record = event.record || event;

const url = record.url || record.normalized_url || '';
const notes = record.notes || '';
const orgId = record.org_id || '';

if (!url) throw new Error('No URL in event payload');

return [{ json: { url, notes, orgId, clientId: record.id, receivedAt: new Date().toISOString() } }];

// Sign the webhook body with HMAC-SHA256
// This node computes the signature using the Web Crypto API (available in n8n Code node)
const payload = $input.first().json;
const rawBody = JSON.stringify({ url: payload.url, notes: payload.notes });
const secret = $env['SCOUT_WEBHOOK_SECRET'];
const ts = Math.floor(Date.now() / 1000);

async function hmacSha256(key, message) {
  const enc = new TextEncoder();
  const cryptoKey = await crypto.subtle.importKey('raw', enc.encode(key), { name: 'HMAC', hash: 'SHA-256' }, false, ['sign']);
  const sig = await crypto.subtle.sign('HMAC', cryptoKey, enc.encode(message));
  return Array.from(new Uint8Array(sig)).map(b => b.toString(16).padStart(2,'0')).join('');
}

const hex = await hmacSha256(secret, `v0:${ts}:${rawBody}`);
const signature = `v0=${hex}`;

return [{ json: { ...payload, rawBody, signature, timestamp: ts } }];

// Parse the run_id from Scout's 202 response
const resp = $input.first().json;
const runId = resp.run_id;
if (!runId) throw new Error('No run_id in Scout response');
return [{ json: { runId, acceptedAt: new Date().toISOString() } }];

// Format summary for Slack notification
const reports = $input.first().json;
const report = Array.isArray(reports) ? reports[0] : reports;
if (!report) return [{ json: { message: 'Run still in progress — check Scout dashboard.' } }];

const ranked = report.ranked || [];
const topOpp = ranked[0];
const shareUrl = report.share_token_hash
  ? `${$env['PUBLIC_APP_URL']}/share/${report.share_token_hash}`
  : `${$env['PUBLIC_APP_URL']}/report/${$('Parse Run ID').first().json.runId}`;

const msg = [
  `*Scout Discovery Complete* :mag:`,
  `*Summary:* ${report.summary?.slice(0, 300) ?? 'N/A'}`,
  topOpp ? `*Top opportunity:* ${topOpp.title} (${topOpp.pillar}, impact ${topOpp.impactScore}/5)` : '',
  `*View report:* ${shareUrl}`
].filter(Boolean).join('\n');

return [{ json: { message: msg, shareUrl } }];

// Error handler — log failure and post a Slack alert
const error = $input.first().json;
const runId = $('Parse Run ID').first()?.json?.runId ?? 'unknown';
const msg = `*Scout pipeline error* :warning:\nRun ID: ${runId}\nError: ${error.message ?? JSON.stringify(error)}`;
return [{ json: { message: msg } }];
